#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    char s[5];
    while(T--){
        scanf(" %4s", s);
        int left = s[0]=='1';
        int right = s[1]=='1';
        int up = s[2]=='1';
        int down = s[3]=='1';
        int xCount = (left?10:0) + (right?10:0) + 1;
        int yCount = (up?10:0) + (down?10:0) + 1;
        printf("%d\n", xCount*yCount);
    }
    return 0;
}

