code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for(int t=0; t<T; t++){
            String s = br.readLine().trim();
            boolean left = s.charAt(0)=='1';
            boolean right = s.charAt(1)=='1';
            boolean up = s.charAt(2)=='1';
            boolean down = s.charAt(3)=='1';
            int xCount = (left?10:0) + (right?10:0) + 1;
            int yCount = (up?10:0) + (down?10:0) + 1;
            sb.append(xCount*yCount);
            if(t<T-1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

